def gather_and_maybe_dequant_cache(
    src_cache: torch.Tensor,
    dst: torch.Tensor,
    block_table: torch.Tensor,
    cu_seq_lens: torch.Tensor,
    token_to_seq: torch.Tensor,
    num_tokens: int,
    kv_cache_dtype: str,
    scale: torch.Tensor,
    seq_starts: torch.Tensor = None,
):
    """Gather tokens from paged KV cache into contiguous destination buffer.

    Supports both direct copy (auto) and FP8 dequantization modes.
    Designed for MLA attention chunked prefill in DeepSeekV2/V4.

    Args:
        src_cache: Paged KV cache [NUM_BLOCKS, BLOCK_SIZE, ENTRY_SIZE]
        dst: Destination buffer [num_tokens, ENTRY_SIZE]
        block_table: Block table mapping [BATCH, max_blocks_per_seq]
        cu_seq_lens: Cumulative sequence lengths [BATCH+1]
        token_to_seq: Token to sequence mapping [num_tokens]
        num_tokens: Number of tokens to gather
        kv_cache_dtype: Cache data type ('auto' or 'fp8_e4m3'/'fp8_e5m2')
        scale: Dequantization scale factor
        seq_starts: Optional sequence start offsets [BATCH]
    """
    logger.debug("GEMS GATHER_AND_MAYBE_DEQUANT_CACHE")

    if num_tokens == 0:
        return

    block_size = src_cache.shape[1]
    entry_size = dst.shape[-1]

    block_table_stride = block_table.stride(0)
    cache_block_stride = src_cache.stride(0)
    cache_entry_stride = src_cache.stride(1)
    dst_entry_stride = dst.stride(0)

    HAS_SEQ_STARTS = seq_starts is not None

    # BLOCK_K=64 divides both 576 (9*64) and 320 (5*64) cleanly
