    grid = (num_tokens,)

    if kv_cache_dtype == "auto":
        _gather_cache_kernel_auto[grid](
            src_cache,
            dst,
            block_table,
            cu_seq_lens,
            token_to_seq,
            seq_starts if HAS_SEQ_STARTS else src_cache,
            num_tokens=num_tokens,
            block_size=block_size,
            block_table_stride=block_table_stride,
            cache_block_stride=cache_block_stride,
            cache_entry_stride=cache_entry_stride,
            dst_entry_stride=dst_entry_stride,
            ENTRY_SIZE=entry_size,
            BLOCK_K=BLOCK_K,
            HAS_SEQ_STARTS=HAS_SEQ_STARTS,
        )
    else:
        _gather_cache_kernel_fp8[grid](
            src_cache,
            dst,
            block_table,
            cu_seq_lens,
            token_to_seq,
            seq_starts if HAS_SEQ_STARTS else src_cache,
            scale,
            num_tokens=num_tokens,
            block_size=block_size,
            block_table_stride=block_table_stride,
            cache_block_stride=cache_block_stride,
            cache_entry_stride=cache_entry_stride,
            dst_entry_stride=dst_entry_stride,
            ENTRY_SIZE=entry_size,
            BLOCK_K=BLOCK_K,
            HAS_SEQ_STARTS=HAS_SEQ_STARTS,
        )
